    holoso_fsgnop#(.WFULL(WFULL)) u_sgnop_a   (.x(a),    .op(a_sgnop),           .y(a1));
    zkf_pipe#(.W(4), .N(LATENCY)) u_out_sgnop_pipe (.clk(clk), .rst(rst), .in_valid(in_valid),
                                                    .in({cos_sgnop, sin_sgnop}), .out_valid(), .out(out_sgnop_q));
