// EMBEDDED FILE BEGIN: zkf_cmp.v

/// Streamed floating-point compare. Equivalent to zkf_cmp_comb with just a single pipeline stage.
///
/// STAGE_INPUT=0: operands feed the compare combinationally (default).
/// STAGE_INPUT=1: latch the inputs before any combinational logic, isolating them from upstream paths (+1 cycle).
/// STAGE_INPUT>1: add extra dummy stages; helps in routing-congested designs (+STAGE_INPUT cycles).

`default_nettype none

module zkf_cmp #(
    parameter WEXP        = 6,
    parameter WMAN        = 18,
    parameter STAGE_INPUT = 0,
    parameter LATENCY     = 0
) (
    input wire clk,
    input wire rst,

    input wire                 in_valid,
    input wire [WEXP+WMAN-1:0] a,
    input wire [WEXP+WMAN-1:0] b,

    output reg out_valid,
    output reg a_gt_b,
    output reg a_eq_b,
    output reg a_lt_b
);
    localparam WFULL = WEXP + WMAN;

    localparam LATENCY_REF = 1 + STAGE_INPUT;
    generate
        if ((LATENCY != 0) && (LATENCY != LATENCY_REF)) begin : g_invalid_latency
            _zkf_invalid_latency_mismatch u_invalid();
        end
    endgenerate

    // -- Optional input register stage: latch the operands before any combinational logic.
    wire             in_valid_q;
    wire [WFULL-1:0] a_q;
    wire [WFULL-1:0] b_q;
    zkf_pipe #(.W(2*WFULL), .N(STAGE_INPUT)) u_input_pipe (
        .clk(clk), .rst(rst), .in_valid(in_valid), .in({b, a}),
        .out_valid(in_valid_q), .out({b_q, a_q})
    );

    wire c_a_gt_b;
    wire c_a_eq_b;
    wire c_a_lt_b;

    zkf_cmp_comb #(.WEXP(WEXP), .WMAN(WMAN)) u_cmp (
        .a(a_q),
        .b(b_q),
        .a_gt_b(c_a_gt_b),
        .a_eq_b(c_a_eq_b),
        .a_lt_b(c_a_lt_b)
    );

    // Reset only stream validity. Payload registers intentionally free-run.
    always @(posedge clk) begin
        if (rst) out_valid <= 1'b0;
        else     out_valid <= in_valid_q;
        a_gt_b <= c_a_gt_b;
        a_eq_b <= c_a_eq_b;
        a_lt_b <= c_a_lt_b;
    end
endmodule

`default_nettype wire

// EMBEDDED FILE END: zkf_cmp.v

// =====================================================================================================================
// EMBEDDED FILE BEGIN: zkf_cmp_comb.v

/// Combinational floating-point compare. Produces three mutually-exclusive one-hot flags.
///
/// Non-canonical zero or infinity bit patterns are still treated per spec: any exponent-zero pattern compares
/// equal to canonical +0, and infinities of the same sign compare equal regardless of input fraction bits.
/// The class-detection paths run in parallel with the wide compare so they do not extend its critical path.
///
/// `a < b` is realized as an explicit subtraction whose borrow-out is the result; this maps directly to the
/// FPGA's carry chain. `a == b` is an XOR-reduce on the same operands; `a > b` is the
/// leftover case. See zkf_cmp for a registered variant.

`default_nettype none

module zkf_cmp_comb #(parameter WEXP = 6, parameter WMAN = 18) (
    input  wire [WEXP+WMAN-1:0] a,
    input  wire [WEXP+WMAN-1:0] b,

    output wire a_gt_b,
    output wire a_eq_b,
    output wire a_lt_b
);
    localparam WFRAC = WMAN - 1;
    localparam WFULL = WEXP + WMAN;

    generate
        if ((WEXP < 2) || (WMAN < 4)) begin : g_invalid_wexp_or_wman
            _zkf_invalid_wexp_or_wman u_invalid();
        end
    endgenerate

    // Build a monotonic comparison key directly from the raw bits, skipping the explicit canonicalization step.
    // Sign-magnitude to ordered-unsigned: invert all bits for negatives, force the sign bit high for non-negatives.
    // Equivalent per-bit form: msb = ~sign, magnitude_bit_i = sign XOR raw_bit_i. The transform has LUT-depth one
    // and runs in parallel with the zero/inf classification below, so the wide compare carry chain no longer waits
    // on `a_zero`/`a_inf`.
    wire [WFULL-1:0] a_key = {~a[WFULL-1], a[WFULL-2:0] ^ {(WFULL-1){a[WFULL-1]}}};
    wire [WFULL-1:0] b_key = {~b[WFULL-1], b[WFULL-2:0] ^ {(WFULL-1){b[WFULL-1]}}};

    // Class detection. Both run in parallel with the wide compare. Any exp-zero pattern decodes as +0 and any
    // exp-all-ones pattern as signed infinity, so non-canonical operands must be folded to canonical equality:
    //   - any two zeros compare equal regardless of stored sign or fraction;
    //   - two infinities with the same sign compare equal regardless of stored fraction.
    wire a_zero        = ~|a[WFULL-2:WFRAC];
    wire b_zero        = ~|b[WFULL-2:WFRAC];
    wire a_inf         =  &a[WFULL-2:WFRAC];
    wire b_inf         =  &b[WFULL-2:WFRAC];
    wire both_zero     = a_zero & b_zero;
    wire same_sign_inf = a_inf & b_inf & ~(a[WFULL-1] ^ b[WFULL-1]);
    wire override_eq   = both_zero | same_sign_inf;

    // Raw key compare. `<` is realized as a zero-extended subtraction whose top bit (borrow-out) is set
    // iff a_key < b_key; this maps to a clean carry chain. `==` is an independent XOR-reduce; `>` is the
    // leftover case. Writing `<` as a `-` keeps the path off whatever wider unsigned-compare lowering the
    // tool might otherwise pick — same trick as `_zkf_add_ge` inside zkf_add.
    // https://stackoverflow.com/q/60844496
    wire [WFULL:0] raw_diff = {1'b0, a_key} - {1'b0, b_key};
    wire raw_lt = raw_diff[WFULL];
    wire raw_eq = a_key == b_key;
    assign a_eq_b = raw_eq | override_eq;
    assign a_lt_b = raw_lt & ~override_eq;
    assign a_gt_b = ~(a_lt_b | a_eq_b);
endmodule

`default_nettype wire

// EMBEDDED FILE END: zkf_cmp_comb.v

// =====================================================================================================================
// EMBEDDED FILE BEGIN: zkf_div.v

/// Streamed Zubax Kulibin float divider. The quotient is rounded by _zkf_pack; div0 is aligned with q/out_valid.
/// div0 reports that the divisor's exponent field is zero (i.e., the divisor encodes +0). It is
/// independent of the quotient: in particular div0 is also asserted for 0/0, where q = +0.
///
/// STAGE_INPUT=0: input combinational paths are exposed.
/// STAGE_INPUT=1: inputs are latched, the external module sees registers at the input (one extra cycle).
/// STAGE_INPUT>1: add extra dummy stages; helps in routing-congested designs (+STAGE_INPUT cycles).
///
/// STAGE_PACK=0: pack inputs are combinational (default).
/// STAGE_PACK=1: register pack inputs (forwarded to _zkf_pack.STAGE_INPUT) (+1 cycle).
///
/// STAGE_OUTPUT=0: q and div0 are combinational (default)
/// STAGE_OUTPUT=1: registered (one extra cycle).

`default_nettype none

module zkf_div #(
    parameter WEXP         = 6,
    parameter WMAN         = 18,   // significand precision including the hidden bit
    parameter STAGE_INPUT  = 0,    // number of input register stages (>=0); +STAGE_INPUT cycles
    parameter STAGE_PACK   = 0,    // 0 = comb pack inputs; 1 = register pack inputs (+1 cycle)
    parameter STAGE_OUTPUT = 0,    // 0 = combinational outputs; 1 = registered outputs (+1 cycle)
    parameter LATENCY      = 0
) (
    input wire clk,
    input wire rst,

    input wire                 in_valid,
    input wire [WEXP+WMAN-1:0] a,
    input wire [WEXP+WMAN-1:0] b,

    output wire                 out_valid,
    output wire [WEXP+WMAN-1:0] q,
    output wire                 div0
);
    localparam WFULL         = WEXP + WMAN;
    localparam WEXP_UNBIASED = WEXP + 2;

    localparam LATENCY_REF = 2 + STAGE_INPUT + ((WMAN+2+((WMAN+2)%2))/2) + STAGE_PACK + STAGE_OUTPUT;
    generate
        if ((LATENCY != 0) && (LATENCY != LATENCY_REF)) begin : g_invalid_latency
            _zkf_invalid_latency_mismatch u_invalid();
        end
    endgenerate

    // Optional input register stage(s): latch the operands before any combinational logic (+STAGE_INPUT cycles).
    wire                in_valid_q;
    wire [2*WFULL-1:0]  pipe_out;
    zkf_pipe #(.W(2*WFULL), .N(STAGE_INPUT)) u_input_pipe (
        .clk(clk), .rst(rst), .in_valid(in_valid), .in({b, a}), .out_valid(in_valid_q), .out(pipe_out)
    );
    wire [WFULL-1:0] a_q = pipe_out[WFULL-1:0];
    wire [WFULL-1:0] b_q = pipe_out[2*WFULL-1:WFULL];

    wire                            core_valid;
    wire                            core_sign;
    wire                            core_force_zero;
    wire                            core_force_inf;
    wire signed [WEXP_UNBIASED-1:0] core_exp_biased;
    // normalized quotient significand.
    wire                 [WMAN-1:0] core_significand;
    wire                            core_guard;
    wire                            core_round;
    wire                            core_sticky;
    wire                            core_div0;

    _zkf_div_core #(.WEXP(WEXP), .WMAN(WMAN)) u_core (
        .clk(clk),
        .rst(rst),
        .in_valid(in_valid_q),
        .a(a_q),
        .b(b_q),
        .out_valid(core_valid),
        .sign(core_sign),
        .force_zero(core_force_zero),
        .force_inf(core_force_inf),
        .exp_biased(core_exp_biased),
        .significand(core_significand),
        .guard(core_guard),
        .round(core_round),
        .sticky(core_sticky),
        .div0(core_div0),
        .exp_diff(),
        .raw(),
        .den(),
        .partial_rem()  // Partial remainder is not used in this module.
    );

    // The packer drives the external q/out_valid directly; STAGE_OUTPUT selects registered vs combinational output.
    _zkf_pack #(
        .WEXP(WEXP), .WMAN(WMAN), .EXP_IS_BIASED(1),
        .STAGE_INPUT(STAGE_PACK), .STAGE_OUTPUT(STAGE_OUTPUT)
    ) u_pack (
        .clk(clk),
        .rst(rst),
        .in_valid(core_valid),
        .sign(core_sign),
        .force_zero(core_force_zero),
        .force_inf(core_force_inf),
        .exp_unbiased(core_exp_biased),
        .significand(core_significand),
        .guard(core_guard),
        .round(core_round),
        .sticky(core_sticky),
        .out_valid(out_valid),
        .y(q)
    );

    // The delay line is a pure free-running datapath (no reset port). See reset policy.
    // STAGE_OUTPUT matches the packer so div0 stays aligned with q.
    _zkf_pack_delay #(
        .W(1), .STAGE_INPUT(STAGE_PACK), .STAGE_OUTPUT(STAGE_OUTPUT)
    ) u_pack_delay (.clk(clk), .x(core_div0), .y(div0));
endmodule

`default_nettype wire

// EMBEDDED FILE END: zkf_div.v

