    wire                 oct_o   = b2_sb[5];
    wire                 tzero_o = b2_sb[4];
    wire                 tiny_o  = b2_sb[3];
    wire                 sa_o    = b2_sb[2];
    wire                 inf_o   = b2_sb[1];
    wire                 sign_o  = b2_sb[0];

