        .WEXP(WEXP), .WMAN(WMAN), .WMAG(WMAG), .WEU(WEU),
        .EXP_IS_BIASED(0), .ASSUME_NO_OVERFLOW(1), .WSB(WSB2),
        .STAGE_NORMALIZE(STAGE_NORMALIZE), .STAGE_PACK(STAGE_PACK), .STAGE_OUTPUT(0)
