        .clk(clk), .rst(rst),
        .in_valid(sh_valid), .sign(sh_sgn), .force_zero(1'b0), .force_inf(sh_inf),
        .exp_offset(sh_exp), .mag(sh_mag), .sb_in(sh_sb),
        .out_valid(be_ov), .y(be_num), .sb_out(be_sbo)
